document.addEventListener('DOMContentLoaded', function() {
    var fileInput = document.getElementById('file-input');
    var settingsPanel = document.getElementById('settings-panel');
    var applyBtn = document.getElementById('apply-btn');
    var resetBtn = document.getElementById('reset-btn');
    var fileList = document.getElementById('file-list');
    var progressSection = document.getElementById('progress-section');
    var progressFill = document.getElementById('progress-fill');
    var progressPercent = document.getElementById('progress-percent');
    var progressText = document.getElementById('progress-text');

    var files = [];
    var processed = false;
    var currentBlob = null;
    var currentFilename = 'archive.tar';

    function showNotification(message, isError) {
        var existing = document.querySelector('.notification');
        if (existing) existing.remove();
        var el = document.createElement('div');
        el.className = 'notification' + (isError ? ' error' : '');
        el.textContent = message;
        document.body.appendChild(el);
        setTimeout(function() { el.remove(); }, 3500);
    }

    function formatSize(bytes) {
        if (bytes < 1024) return bytes + ' B';
        if (bytes < 1048576) return (bytes / 1024).toFixed(1) + ' KB';
        return (bytes / 1048576).toFixed(1) + ' MB';
    }

    function renderFileList() {
        if (files.length === 0) {
            fileList.innerHTML = '';
            applyBtn.disabled = true;
            settingsPanel.classList.remove('show');
            return;
        }
        settingsPanel.classList.add('show');
        applyBtn.disabled = false;
        var html = '';
        for (var i = 0; i < files.length; i++) {
            html += '<div class="file-item"><span class="file-name">' + files[i].name + '</span><span class="file-size">' + formatSize(files[i].size) + '</span><button class="remove-btn" data-index="' + i + '" aria-label="Remove ' + files[i].name + '"><svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M18 6L6 18M6 6l12 12"/></svg></button></div>';
        }
        fileList.innerHTML = html;
        var removeBtns = fileList.querySelectorAll('.remove-btn');
        for (var j = 0; j < removeBtns.length; j++) {
            removeBtns[j].addEventListener('click', function() {
                files.splice(parseInt(this.dataset.index), 1);
                renderFileList();
            });
        }
    }

    function showDownloadSection(filename, blob) {
        currentBlob = blob;
        currentFilename = filename;
        var old = document.getElementById('result-section');
        if (old) old.remove();

        var section = document.createElement('div');
        section.id = 'result-section';
        section.style.cssText = 'margin-top:var(--space-4);padding:var(--space-4);background:#f0fdf4;border:1px solid #bbf7d0;border-radius:12px;display:block';
        section.innerHTML =
            '<div style="display:flex;align-items:center;gap:var(--space-3);margin-bottom:var(--space-3)">' +
                '<i class="fas fa-check-circle" style="color:#16a34a;font-size:1.5rem"></i>' +
                '<div><div style="font-weight:600;color:#166534">Archive Ready!</div>' +
                '<div style="font-size:var(--text-sm);color:var(--color-text-light)">' + filename + ' (' + formatSize(blob.size) + ')</div></div>' +
            '</div>' +
            '<button id="download-btn" class="btn btn-primary btn-lg" style="width:100%"><i class="fas fa-download"></i> Download ' + filename + '</button>';

        settingsPanel.insertBefore(section, settingsPanel.firstChild);

        document.getElementById('download-btn').addEventListener('click', function() {
            var url = URL.createObjectURL(currentBlob);
            var a = document.createElement('a');
            a.href = url;
            a.download = currentFilename;
            document.body.appendChild(a);
            a.click();
            setTimeout(function() { document.body.removeChild(a); URL.revokeObjectURL(url); }, 100);
            showNotification(currentFilename + ' downloaded!');
        });

        applyBtn.style.display = 'none';
        progressSection.style.display = 'none';
        processed = true;
    }

    function formatOctal(num, size) {
        var str = num.toString(8);
        while (str.length < size - 1) str = '0' + str;
        str += '\0';
        return str;
    }

    function createTarEntry(name, data) {
        var header = new Uint8Array(512);
        var offset = 0;

        for (var i = 0; i < name.length && i < 100; i++) {
            header[offset++] = name.charCodeAt(i);
        }
        offset = 100;

        var mode = '00000644\0';
        for (var m = 0; m < mode.length; m++) header[offset++] = mode.charCodeAt(m);
        offset = 108;

        var uid = '0000000\0';
        for (var u = 0; u < uid.length; u++) header[offset++] = uid.charCodeAt(u);
        offset = 116;

        var gid = '0000000\0';
        for (var g = 0; g < gid.length; g++) header[offset++] = gid.charCodeAt(g);
        offset = 124;

        var sizeStr = formatOctal(data.length, 12);
        for (var s = 0; s < 12; s++) header[offset++] = sizeStr.charCodeAt(s);
        offset = 136;

        var mtime = formatOctal(Math.floor(Date.now() / 1000), 12);
        for (var t = 0; t < 12; t++) header[offset++] = mtime.charCodeAt(t);
        offset = 148;

        header[offset] = 48;
        header[offset + 1] = 0;

        var checksum = 0;
        for (var c = 0; c < 512; c++) {
            checksum += header[c];
        }
        var checksumStr = formatOctal(checksum + 256, 7);
        for (var q = 0; q < 7; q++) header[148 + q] = checksumStr.charCodeAt(q);
        header[155] = 0;

        return header;
    }

    var dropZone = document.querySelector('.upload-area');
    if (dropZone) {
        dropZone.addEventListener('dragover', function(e) { e.preventDefault(); dropZone.style.borderColor = 'var(--color-primary)'; });
        dropZone.addEventListener('dragleave', function() { dropZone.style.borderColor = ''; });
        dropZone.addEventListener('drop', function(e) {
            e.preventDefault();
            dropZone.style.borderColor = '';
            if (e.dataTransfer.files.length) {
                for (var i = 0; i < e.dataTransfer.files.length; i++) {
                    files.push(e.dataTransfer.files[i]);
                }
                renderFileList();
            }
        });
    }

    fileInput.addEventListener('change', function(e) {
        for (var i = 0; i < e.target.files.length; i++) {
            files.push(e.target.files[i]);
        }
        renderFileList();
        fileInput.value = '';
    });

    applyBtn.addEventListener('click', function() {
        if (files.length === 0) return;

        var old = document.getElementById('result-section');
        if (old) old.remove();
        processed = false;

        progressSection.style.display = 'block';
        applyBtn.disabled = true;
        progressText.textContent = 'Reading files...';
        progressFill.style.width = '20%';
        progressPercent.textContent = '20%';

        var fileDataList = [];
        var loaded = 0;
        var total = files.length;

        function readFile(index) {
            if (index >= total) {
                createTar(fileDataList);
                return;
            }
            var reader = new FileReader();
            reader.onload = function(ev) {
                fileDataList.push({ name: files[index].name, data: new Uint8Array(ev.target.result) });
                loaded++;
                progressFill.style.width = (20 + 30 * (loaded / total)) + '%';
                progressPercent.textContent = Math.round(20 + 30 * (loaded / total)) + '%';
                readFile(index + 1);
            };
            reader.readAsArrayBuffer(files[index]);
        }

        function createTar(dataList) {
            try {
                var totalSize = 0;
                for (var i = 0; i < dataList.length; i++) {
                    totalSize += 512 + Math.ceil(dataList[i].data.length / 512) * 512;
                }
                totalSize += 1024;

                var tarData = new Uint8Array(totalSize);
                var offset = 0;

                progressText.textContent = 'Creating TAR...';
                progressFill.style.width = '60%';
                progressPercent.textContent = '60%';

                for (var j = 0; j < dataList.length; j++) {
                    var entry = createTarEntry(dataList[j].name, dataList[j].data);
                    tarData.set(entry, offset);
                    offset += 512;

                    tarData.set(dataList[j].data, offset);
                    var paddedSize = Math.ceil(dataList[j].data.length / 512) * 512;
                    offset += paddedSize;
                }

                for (var p = 0; p < 1024; p++) tarData[offset + p] = 0;

                progressFill.style.width = '80%';
                progressPercent.textContent = '80%';
                progressText.textContent = 'Encoding...';

                var blob = new Blob([tarData], { type: 'application/x-tar' });

                progressFill.style.width = '100%';
                progressPercent.textContent = '100%';
                progressText.textContent = 'Done!';

                showDownloadSection('archive.tar', blob);
                showNotification('TAR archive created successfully!');
            } catch (err) {
                showNotification('Error creating TAR: ' + err.message, true);
                applyBtn.disabled = false;
                progressSection.style.display = 'none';
            }
        }

        readFile(0);
    });

    resetBtn.addEventListener('click', function() {
        files = [];
        processed = false;
        currentBlob = null;
        var old = document.getElementById('result-section');
        if (old) old.remove();
        renderFileList();
        progressSection.style.display = 'none';
        applyBtn.style.display = '';
        applyBtn.disabled = true;
    });
});
